const data = $json;

function getHeader(name) {
  const headers = data.payload?.headers || data.headers || [];
  const found = headers.find(h => String(h.name || '').toLowerCase() === name.toLowerCase());
  return found?.value || '';
}

const subject = getHeader('Subject') || data.subject || 'Website contact form';
const from = getHeader('From') || data.from || 'Not informed';
const date = getHeader('Date') || data.date || new Date().toLocaleString('pt-BR');

const rawText =
  data.textPlain ||
  data.text ||
  data.snippet ||
  data.body ||
  JSON.stringify(data);

function extract(label) {
  const regex = new RegExp(label + ':\\s*(.*?)(?=\\s(?:Data|App|Store|Sent by|Name|Email|CPF|CNPJ|Subject|Message|About):|$)', 'i');
  const match = rawText.match(regex);
  return match ? match[1].trim() : '';
}

const name = extract('Sent by') || extract('Name') || from;
const email = extract('Email') || 'Not informed';
const store = extract('Store') || 'Not informed';
const message = extract('About') || extract('Message') || rawText;

return [{
  json: {
    text: `New website contact form message\n\nName: ${name}\nEmail: ${email}\nStore: ${store}\nSubject: ${subject}\nDate: ${date}\n\nMessage:\n${message}`
  }
}];
